namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private OrderService _service = null!;

    [TestInitialize]
    public void Setup()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string Name, decimal Price, int Qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.Name, Price = i.Price, Quantity = i.Qty }).ToList();

    // ── CreateOrder ────────────────────────────────────────────────

    [TestMethod]
    public void CreateOrder_SingleItem_ReturnsOrderWithCorrectTotal()
    {
        var items = CreateItems(("Widget", 9.99m, 3));

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(29.97m, order.Total);
        Assert.AreEqual(1, order.Items.Count);
        Assert.IsFalse(string.IsNullOrEmpty(order.Id));
    }

    [TestMethod]
    public void CreateOrder_MultipleItems_SumsTotalCorrectly()
    {
        var items = CreateItems(("A", 10m, 2), ("B", 5m, 4));

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual(40m, order.Total); // (10*2) + (5*4)
        Assert.AreEqual(2, order.Items.Count);
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToRecentUtcTime()
    {
        var before = DateTime.UtcNow;
        var order = _service.CreateOrder("cust-1", CreateItems(("X", 1m, 1)));
        var after = DateTime.UtcNow;

        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after);
    }

    [TestMethod]
    public void CreateOrder_GeneratesUniqueIds()
    {
        var items = CreateItems(("X", 1m, 1));

        var order1 = _service.CreateOrder("cust-1", items);
        var order2 = _service.CreateOrder("cust-1", items);

        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _service.CreateOrder(null!, CreateItems(("X", 1m, 1))));
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _service.CreateOrder("cust-1", null!));
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));
    }

    // ── GetOrder ───────────────────────────────────────────────────

    [TestMethod]
    public void GetOrder_ExistingOrder_ReturnsOrder()
    {
        var created = _service.CreateOrder("cust-1", CreateItems(("X", 5m, 1)));

        var found = _service.GetOrder(created.Id);

        Assert.IsNotNull(found);
        Assert.AreEqual(created.Id, found.Id);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        var result = _service.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    // ── GetOrdersByCustomer ────────────────────────────────────────

    [TestMethod]
    public void GetOrdersByCustomer_ReturnsOnlyMatchingOrders()
    {
        _service.CreateOrder("cust-1", CreateItems(("A", 1m, 1)));
        _service.CreateOrder("cust-2", CreateItems(("B", 2m, 1)));
        _service.CreateOrder("cust-1", CreateItems(("C", 3m, 1)));

        var orders = _service.GetOrdersByCustomer("cust-1");

        Assert.AreEqual(2, orders.Count);
        Assert.IsTrue(orders.All(o => o.CustomerId == "cust-1"));
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoOrders_ReturnsEmptyList()
    {
        var orders = _service.GetOrdersByCustomer("nobody");

        Assert.AreEqual(0, orders.Count);
    }
}

